package com.hospital.management.controller.admission;import com.hospital.management.model.Room;import com.hospital.management.service.*;import com.hospital.management.service.impl.RoomServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.*;@WebServlet("/admin/rooms/view")public class RoomViewServlet extends HttpServlet{private final RoomService s;public RoomViewServlet(){this(new RoomServiceImpl());}RoomViewServlet(RoomService s){this.s=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=AdmissionRequest.id(q.getParameter("id"));if(id==null){r.sendError(400);return;}Room x=s.getRoom(id).orElse(null);if(x==null){r.sendError(404);return;}q.setAttribute("room",x);q.getRequestDispatcher("/WEB-INF/views/admin/rooms/view.jsp").forward(q,r);}}
